import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    """
    {This algorithm employs dynamic prioritization by calculating a prospective score based on inverse distance_weighted prioritization, 
    urgency in time window constraints, and congestion avoidance, focusing on reducing overlap in clusters while ensuring timely visits.}
    """
    def euclidean_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    best_node = None
    min_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        distance_to_customer = euclidean_distance(cur_truck_pos, customer)
        arrival_time = current_time + (distance_to_customer / truck_speed)

        if arrival_time > time_windows[i][1]:
            continue

        waiting_time = max(0, time_windows[i][0] - arrival_time)
        time_window_urgency = max(0, time_windows[i][1] - current_time)
        congestion_avoidance_score = len([1 for pos in all_truck_pos if euclidean_distance(customer, pos) < distance_to_customer])

        score = distance_to_customer - (1 / (1 + waiting_time)) - (1 / (1 + time_window_urgency)) + congestion_avoidance_score

        if score < min_score:
            min_score = score
            best_node = i

    if best_node is None:
        best_node = 'None'

    return best_node

